import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Form, Button, Container } from "react-bootstrap";
import axios from "axios";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [drug, setDrug] = useState({
        medicine_name: "",
        medicine_type_name: "",
        price: 0,
        unit: "",
        description: "",
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetchDrug();
    }, []);

    const fetchDrug = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            setDrug(response.data);
            setLoading(false);
        } catch (error) {
            console.error("Lỗi khi lấy thông tin thuốc:", error);
            setError("Không thể tải thông tin thuốc.");
            setLoading(false);
        }
    };

    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    const handleSave = async () => {
        try {
            await axios.put(`http://localhost:5001/api/medicine/${id}`, drug);
            navigate("/drug");
        } catch (error) {
            console.error("Lỗi khi cập nhật thuốc:", error);
        }
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <Container className="mt-4">
            <h4>Chỉnh Sửa Thuốc</h4>
            <Form>
                <Form.Group className="mb-3">
                    <Form.Label>Tên thuốc</Form.Label>
                    <Form.Control
                        name="medicine_name"
                        value={drug.medicine_name}
                        onChange={handleChange}
                    />
                </Form.Group>
                <Form.Group className="mb-3">
                    <Form.Label>Loại thuốc</Form.Label>
                    <Form.Control
                        name="medicine_type_name"
                        value={drug.medicine_type_name}
                        onChange={handleChange}
                    />
                </Form.Group>
                <Form.Group className="mb-3">
                    <Form.Label>Giá (VNĐ)</Form.Label>
                    <Form.Control
                        type="number"
                        name="price"
                        value={drug.price}
                        onChange={handleChange}
                    />
                </Form.Group>
                <Form.Group className="mb-3">
                    <Form.Label>Đơn vị tính</Form.Label>
                    <Form.Control
                        name="unit"
                        value={drug.unit}
                        onChange={handleChange}
                    />
                </Form.Group>
                <Form.Group className="mb-3">
                    <Form.Label>Mô tả</Form.Label>
                    <Form.Control
                        as="textarea"
                        rows={3}
                        name="description"
                        value={drug.description}
                        onChange={handleChange}
                    />
                </Form.Group>
                <Button variant="secondary" onClick={() => navigate("/drugr")}>Thoát</Button>
                <Button variant="primary" className="ms-2" onClick={handleSave}>Lưu</Button>
            </Form>
        </Container>
    );
};

export default EditDrug;
